s3 = boto3.client("s3")
dynamodb = boto3.resource("dynamodb")
sns = boto3.client("sns")
sqs = boto3.client("sqs")


def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    action = event.get("action", "noop")
    bucket = os.environ.get("BUCKET_NAME", "")
    table_name = os.environ.get("TABLE_NAME", "")
    topic_arn = os.environ.get("TOPIC_ARN", "")
    queue_url = os.environ.get("QUEUE_URL", "")

    result: Dict[str, Any] = {"action": action, "status": "ok"}

    if action == "read_s3" and bucket:
        key = event.get("key", "")
        obj = s3.get_object(Bucket=bucket, Key=key)
        result["s3_body"] = obj["Body"].read().decode("utf-8")

    elif action == "write_dynamodb" and table_name:
        table = dynamodb.Table(table_name)
        item = event.get("item", {"id": "default"})
        table.put_item(Item=item)
        result["dynamodb"] = "written"

    elif action == "publish_sns" and topic_arn:
        message = event.get("message", "hello")
        sns.publish(TopicArn=topic_arn, Message=message)
        result["sns"] = "published"

    elif action == "send_sqs" and queue_url:
        message = event.get("message", "hello")
        sqs.send_message(QueueUrl=queue_url, MessageBody=message)
        result["sqs"] = "sent"

    return {
        "statusCode": 200,
        "body": json.dumps(result),
    }